from collections import defaultdict

class Solution(object):
    def countGoodNodes(self, edges):
        n = len(edges) + 1
        adj = defaultdict(list)
        for a, b in edges:
            adj[a].append(b)
            adj[b].append(a)
        good = [0]
        def dfs(u, parent):
            sizes = []
            for v in adj[u]:
                if v != parent:
                    sizes.append(dfs(v, u))
            if not sizes or len(set(sizes)) == 1:
                good[0] += 1
            return sum(sizes) + 1
        dfs(0, -1)
        return good[0]
